function func() {
  var el = {{clickElement}};
  var txt = el ? el.innerText : '';
  var tit = el && el.title;
  var url = location.pathname;
  var n_replace = {{FC_nthReplace}};
  const cd = {{customData}};

  if (cd && cd.click_text){
    return cd.click_text;
  }

  if (el ){
    if (el.querySelector(".tit")){
      txt = el.querySelector(".tit").innerText;
    } else if (el.querySelector("img") && el.querySelector("img").alt){
      txt = el.querySelector("img").alt;
    } else if (el.matches("img") && el.alt){
      txt = el.alt;
    } else if (el.querySelector('[class*=main-title]')) {
      txt = el.querySelector('[class*=main-title]').innerText;
    } else if (el && el.closest('.whistle-button-my-page')){
      txt = '프로필';
    } else if (el.matches('.store-button-alarm')){
      txt = '알림 버튼';
    } else if (el.closest('.favorite-button.btn-like')){
      txt = '찜하기';
    } else if (el && !txt){
      txt = el.textContent;
    }

    if (el.className === 'mypage-main__life-cart'){
      txt = '장바구니';
    } else if (el.querySelector('.quickmenu__name')){
      txt = el.querySelector('.quickmenu__name').innerText;
    }

    if (el && el.closest('.main-header__left') && el.querySelector('.title')) {
      txt = el.querySelector('.title').innerText;
    }

    txt = tit || txt;
    if (el && el.matches('.category-detail__more-button')){
      if (txt.match('더보기')){
        txt = txt.replace(/더보기/,'접기');
      } else if (txt.match('접기')){
        txt = txt.replace(/접기/,'더보기');
      }
    }

    if (location.pathname.match('myPage') && el.closest('.my-page__basic-point-section > li')){
        txt = el.closest('.my-page__basic-point-section > li').querySelector('span')? el.closest('.my-page__basic-point-section > li').querySelector('span').innerText : '';
      }

    if (url.includes('/whistle/main') && el.closest('.whistle-task-header__modal-content')){ //휘슬 메인 할일 팝업창 내 요소
      const p = el.querySelector('.whistle-task-header__modal-content-item-info-desc');
      txt = p ? p.innerText : '';
    }


    // 마이페이지
    if (txt == '프로필 이미지'){
      txt = '프로필';
    } else if (el.closest('.mypage-section-container__menu-list')){
      txt = '더보기';
    } else if (url.includes('myPage') && el.closest('.mypage-main__information')){
      txt = txt.replace(/\d{1,3}(,\d{3})*[원C]$|\d+[원C]$/, '');
    } else if (el.matches('.mypage-section-container__title')){
      txt = '더보기';
    } else if (el.matches('.mypage-section-container__whistle-empty-regist') && el.querySelector('.mypage-section-container__whistle-empty-regist-right')){
      txt = el.querySelector('.mypage-section-container__whistle-empty-regist-right').innerText;
    }

    // 상품 상세페이지
    if (location.pathname.includes('/product/detail/')){
      // 리뷰 - 4점이상 리뷰
      if (el.matches('[data-id="product-detail__feedback-above-four-item"]')){
        var review_score = el.querySelector('.review-rating > .count') ? el.querySelector('.review-rating > .count').innerText : '';
        var review_content = el.querySelector('.txt') ? el.querySelector('.txt').innerText : '';

        var review_type =  review_content ? review_content.replace(/^(영상후기|일반후기|포토후기).*$/, '$1') : ''; 

        review_content = review_content ? review_content.replace(/^(일반후기|포토후기|영상후기)/, '') : '';
        txt = review_content + '___' + review_score + '___' + review_type;
      }

      // 리뷰 - 사진&영상 리뷰
      if (el.matches('.photo-and-video-review__list-item')){
        if (el.querySelector('.review-video-thumbnail-container')){
          txt = '영상후기';
        } else if (el.querySelector('[alt="리뷰 이미지"]')){
          txt = '포토후기';
        }
      }

      // 리뷰 - 베스트리뷰
      else if (el.matches('.best-review__card')){
        var review_score = el.querySelector('.review-rating-score') ? el.querySelector('.review-rating-score').innerText : '';
        var review_content = el.querySelector('.review-preview-text') ? el.querySelector('.review-preview-text').innerText : '';

        var review_date = el.querySelector('.review-preview-date') ? el.querySelector('.review-preview-date').innerText : '';

        txt = review_content + '___' + review_score + '___구분불가___' + review_date;

      // 리뷰어 프로필
      } else if (el.matches('.profile-container')){
        txt = el.querySelector('.profile-name') ? el.querySelector('.profile-name').innerText : '';
      }

    // 리뷰어 랭킹페이지  
    } else if (location.pathname.includes('/myPage/review/reviewerranking')){
      // 리뷰
      if (el.matches('.reviewer-ranking-preview-card-container')){
        var review_score = el.querySelector('.review-rating-score') ? el.querySelector('.review-rating-score').innerText : '';
        var review_content = el.querySelector('.review-preview-text') ? el.querySelector('.review-preview-text').innerText : '';

        if (el.querySelector('.review-video-thumbnail-container')){
          var review_type = '영상후기';
        } else if (el.querySelector('[alt*="리뷰 이미지"]')){
          var review_type = '포토후기';
        } else {
          var review_type = '일반후기';
        }

        var review_date = el.querySelector('.review-preview-date') ? el.querySelector('.review-preview-date').innerText : '';

        txt = review_content + '___' + review_score + '___' + review_type + '___' + review_date;

      // 리뷰어 프로필
      } else if (el.matches('.reviewer-ranking-ranking-item')){
        txt = el.querySelector('.review-profile-section__profile-name > span') ? el.querySelector('.review-profile-section__profile-name > span').innerText : '';
      }

    // 커머스 검색전 페이지 - 리뷰어가 추천하는 제품 영역
    } else if (location.pathname.includes('/search') && el.matches('.review-recomm-item')){
      var review_content = el.querySelector('.review-recomm-item > div:nth-of-type(2) > div:nth-of-type(2)');

      txt = review_content ? review_content.innerText : '';

    // 상품 상세페이지, 4점이상 리뷰 페이지, 베스트리뷰 페이지, 리뷰 상세보기 페이지, 리뷰어 프로필 페이지, 브랜드스토어 리뷰탭 페이지
    } else if (location.pathname.includes('/product/detail/') || 
               location.pathname.includes('/myPage/review/abovefourdetail') || 
               location.pathname.includes('/myPage/review/bestreviewdetail') || 
               location.pathname.includes('/myPage/review/reviewdetail') || 
               location.pathname.includes('/myPage/review/reviewerProfile') ||
               location.pathname.includes('/store/')
               ){

      // 리뷰 - 전체리뷰 -> 클릭시 이동없음.
      if (el.matches('.review-content') && el.closest('.common-review-item-container')){
        var review_score = el.closest('.common-review-item-container').querySelector('.rating-score') ? el.closest('.common-review-item-container').querySelector('.rating-score').innerText : '';

        if (el.closest('.common-review-item-container').querySelector('.video-container')){
          var review_type = '영상후기';
        } else if (el.closest('.common-review-item-container').querySelector('[alt*="리뷰 이미지"]')){
          var review_type = '포토후기';
        } else {
          var review_type = '일반후기';
        }

        var review_content = el.querySelector('.review-text') ? el.querySelector('.review-text').innerText : '';
        var review_date = el.closest('.common-review-item-container').querySelector('.review-date') ? el.closest('.common-review-item-container').querySelector('.review-date').innerText.split('\n')[0] : '';

        txt = review_content + '___' + review_score + '___' + review_type + '___' + review_date;

      // 리뷰어 프로필
      } else if (el.matches('.review-common-profile-section-container')){
        txt = el.querySelector('.review-profile-section__profile-name > span') ? el.querySelector('.review-profile-section__profile-name > span').innerText : '';
      // 리뷰어 프로필
      } else if (el.matches('.profile-container')){
        txt = el.querySelector('.profile-name') ? el.querySelector('.profile-name').innerText : '';
      }
    }
  }
  txt = n_replace(txt);
  // txt && console.log('NTH >> 클릭 텍스트 : ' + txt);
  return txt;
}

function func() {
    let el = {{clickElement}};
    const cd = {{customData}};
    const likes = {{AL_likeBtn_arr}};
    if (el && likes.some(cls => el.classList.contains(cls))) {
      el = el.closest('a') || null;
    }
    let brand = '';

    if (cd && cd.prd_brand) {
      // PAGE LOAD
      brand = cd.prd_brand;
    }else if (el) {
      // CLICK
      const titles = ['.store', '.common-review-brand-name', '.recent-goods-store-name', '.ranking-goods-brand'];
      const selector = titles.join(', ');
      const elBrand = el.querySelector(selector);
      brand = elBrand ? elBrand.innerText : '';
    }
    if (location.pathname.match('order/cart') && document.querySelector('div[data-goods-id]')){
     if ( el && el.matches('.cart-selected-goods__total-button')){
       var goods = document.querySelectorAll('.cart-selected-goods__store-name');
       var brands = [];
        goods.forEach((e) => {brands.push(e.innerText);});
        brand = brands.join('___');
     }else{
     if (el && el.closest('div[data-goods-id]')) el = el.closest('div[data-goods-id]');
     if (el && el.querySelector('.cart-selected-goods__store-name')) brand = el.querySelector('.cart-selected-goods__store-name').innerText;
     }
    }else if(location.pathname.match('order/payment') && document.querySelector('.store-name')){
      if (!el || el.matches('.order-payment__payment-button')){
        var goods = document.querySelectorAll('.store-name');
        var titles = [];
        goods.forEach((e) => {titles.push(e.innerText);});
        brand = titles.join('___');
      }
    }else if(!el && location.pathname.match('myPage/recentGoods') && document.querySelector('.recent-goods-store-name')){
        var goods = document.querySelectorAll('.recent-goods-store-name');
        var titles = [];
        goods.forEach((e) => {titles.push(e.innerText);});
        brand = titles.join('___');
    }else if (el && el.matches('.recent-order-item') && el.querySelector('.recent-order-item__detail-desc__store-name')){
     brand = el.querySelector('.recent-order-item__detail-desc__store-name').innerText.trim();
    }else if(location.pathname.match('/main/deal') && el && el.querySelector('.timedeal-item__title')){
     var tmp = el.querySelector('.timedeal-item__title').innerText.split(']');
      if(tmp && tmp.length > 1){
        brand = tmp[0].replace(/\[/g,'');
      }
    }else if ( (!el || (el && !el.closest('.product-item'))) && location.pathname.match('product/detail') &&  document.querySelector('.prod-item__display-name')){
      var prdel = document.querySelector('.prod-item__display-name').parentElement;
      brand = prdel.querySelector('div > p') ? prdel.querySelector('div > p').innerText: '';
    }else if (location.pathname.match('reviewerProfile') && el && el.closest('[data-goods-id]')){
     brand = el.closest('[data-goods-id]').querySelector('.common-review-brand-name') ? el.closest('[data-goods-id]').querySelector('.common-review-brand-name').innerText : '';
   }else if (el && !brand && el.closest('.common-review-goods-container,.common-review-item-container ') && el.closest('.common-review-goods-container,.common-review-item-container ').querySelector('.common-review-brand-name')){
       brand = el.closest('.common-review-goods-container,.common-review-item-container ').querySelector('.common-review-brand-name').innerText;
    }

    return brand;
}

function func() {
    let el = {{clickElement}};
    const likes = {{AL_likeBtn_arr}};
    if (el && likes.some(cls => el.classList.contains(cls))) {
      el = el.closest('a') || null;
    }
    const cd = {{customData}};

    let code = '';
    if (cd && cd.act_type === 'pageview' && cd.prd_code) {
        code = cd.prd_code;
    } else if (el) {
    // CLICK
    let href = '';
    if (el.tagName.toLowerCase() === 'a') {
       href = el.href;
    } else {
       href = {{url}};
    }
    const word = "/product/detail/";
    let startIdx = href.indexOf(word);
    if (startIdx > 0) {
      startIdx = startIdx + word.length;
      code = href.substring(startIdx);
    }
    if (code && el.closest('.store-profile__util')){
      return code.split('?')[0];
    }else if (location.pathname.match('product/detail') && el.closest('.store-profile__link')){
        code = location.pathname.match('product/detail/(.+)')[1];
    }
   } else if (!el && location.pathname.match('product/detail')){
     code = location.pathname.match('/product/detail/(.+)')[1];
   }

   if (location.pathname.match('(order/cart|order/payment)') && document.querySelector('div[data-goods-id],li[data-order-goodsid]')){
     if (el && el.closest('div[data-goods-id]')) code = el.closest('div[data-goods-id]').dataset.goodsId;
     else if ( !el || (el && el.matches('.cart-selected-goods__total-button, .order-payment__payment-button'))){
       var codes = [];
       if(document.querySelector('div[data-goods-id]')){
         var goods = document.querySelectorAll('div[data-goods-id]');
          goods.forEach((e) => {codes.push(e.dataset.goodsId);});
          code = codes.join('___');
       }else if(document.querySelector('li[data-order-goodsid]')){
         var goods = document.querySelectorAll('li[data-order-goodsid]');
          goods.forEach((e) => {codes.push(e.dataset.orderGoodsid);});
          code = codes.join('___');
       }
     }
   }else if (location.pathname.match('(favorite|recentGoods)')){
     var codes = [];
     if (!el && document.querySelector('a.recent-goods-item-button')){
       var goods = document.querySelectorAll('a.recent-goods-item-button');
       goods.forEach((e) => {
         var url = e.href && e.href.split('/');
         if (url && url.includes('detail')){
           codes.push(url[url.length -1]);
         }
       });

       code = codes.join('___');
     }else if(el && el.closest('a.recent-goods-item-button')){
       var url = el.closest('a.recent-goods-item-button').href && el.closest('a.recent-goods-item-button').href.split('/');
       code = url[url.length -1];
     }
   }else if (location.pathname.match('reviewerProfile') && el && el.closest('[data-goods-id]')){
     code = el.closest('[data-goods-id]').dataset.goodsId;
   }

   if (el && !code && el.closest('.review-recomm-item') && el.querySelector('[data-product-item-id]')){
       code = el.querySelector('[data-product-item-id]').dataset.productItemId;
   }else if (el && !code && el.closest('.common-review-goods-container, .common-review-item-container') && el.closest('[data-goods-id]')){
       code = el.closest('[data-goods-id]').dataset.goodsId;
   }

   if (!code && el && el.closest('[data-goods-id]')) code = el.closest('[data-goods-id]').dataset.goodsId;
  return code.split('?')[0];

}

function func() {
   const el = {{clickElement}};
   const path = {{path}};
   const cd = {{customData}};
   const spage_id = sessionStorage.getItem('nth_page_id');
   const ssrch_kwd = sessionStorage.getItem('nth_srch_kwd');
   // console.log('검색키워드 체크 구문 시작', spage_id);
   if (cd && cd.srch_kwd) {
     return cd.srch_kwd;
   }

   if (el && el.closest('.search-header__icon-close, .recommend-keyword__list-wrap')) {
     // 통합검색 검색창 x버튼 검색어 수집 제외
     // 통합검색 검색 전 페이지 추천 검색어 수집 제외
     return '';
   }

   let kwd = '';
   const searchEl = document.querySelector("input.search-header__input");
   if (!el && path.includes('search') && searchEl ) {
     kwd = searchEl.value ? searchEl.value : searchEl.getAttribute('placeholder');
     return kwd;
   }else if (!el){
     return '';
   }

   if (el.matches('.search-recent-keyword-chip, .search-result__related-keyword-chip')) {
     return el.innerText.trim();
   }else if(location.pathname.match('/search/result') && el.querySelector('.is-bottom-line-stretch')){
     return el.querySelector('.is-bottom-line-stretch').trim();
   }

   const kwdEl = el.querySelector('.ranking-keyword') || el.querySelector('.popular-keyword__keyword');
   if (kwdEl) {
     kwd = kwdEl.innerText.trim() || '';
   } else if (el.classList.contains('svg')) {
     const wrapper = el.closest('div');
     const inputEl = wrapper && (wrapper.querySelector('input.search-input') || wrapper.querySelector('input.search-header__input'));
     kwd = inputEl && inputEl.value ? inputEl.value : inputEl.placeholder;
   }else if (el.matches('.ranking-keyword__title')){
     kwd = el.innerText.trim();
   }

   // 통합검색
   if (el.className === 'related-search__link') {
     kwd = el.innerText;
   }

   if (spage_id && spage_id.includes('search')) {
     // console.log('변수 : 스토어 검색결과 키워드 수집');
     const inputEl = document.querySelector('input.search-header__input');
     // console.log('변수 : 스토어 검색결과 키워드 수집_inputEl', inputEl);
     if (el && inputEl) {
       kwd = inputEl && inputEl.value ? inputEl.value : inputEl.getAttribute('placeholder');
       // console.log('변수 : 스토어 검색결과 키워드 수집_kwd_1', kwd);
     } else if (el) {
       kwd = ssrch_kwd;
       // console.log('변수 : 스토어 검색결과 키워드 수집_kwd_2', kwd);
     }

   }

   return kwd;
}

function func() {
    const cd = {{customData}};
    var el = {{clickElement}};

    let tabName = '';

   if ( el && el.matches('.main-header__left')) {
     return '';
   }
    // 알림함
    if ( el && el.closest('.alarm-list__container')) {
      const tabEl = document.querySelector('.tab-label.is-selected');
      tabName = tabEl ? tabEl.innerText : '';
    }

    // 커머스 - 공용 아이콘 버튼 클릭 시
    if (el && el.closest('.main-header')){
      const parent = el.closest('.main-header').parentElement;
      const activeTab = parent && parent.querySelector('.tab-navigation__menu.is-active');
      tabName = activeTab ? activeTab.innerText : '';
    }

    // 휘슬 - 탭 클릭 시, 카드 클릭 시, 상품, 찜하기 
    if (el && el.querySelector('.tab-label.is-selected')){
      tabName = el.querySelector('.tab-label.is-selected') && el.querySelector('.tab-label.is-selected').innerText;
    } else if (el && el.closest('.whistle-main__card-view')){
      tabName = document.querySelector('.tab-label.is-selected') && document.querySelector('.tab-label.is-selected').innerText;
    } else if (el && el.closest('.whistle-main__quick-menu')){
      tabName = document.querySelector('.tab-label.is-selected') && document.querySelector('.tab-label.is-selected').innerText;
    } else if (el && el.closest('.product-item')){
      tabName = document.querySelector('.tab-label.is-selected') && document.querySelector('.tab-label.is-selected').innerText;
    } else if (el && el.closest('.favorite-button')){
      tabName = document.querySelector('.tab-label.is-selected') && document.querySelector('.tab-label.is-selected').innerText;
    } else if (el && el.closest('.whistle-main-shopping__title-top-right')){
      tabName = document.querySelector('.tab-label.is-selected') && document.querySelector('.tab-label.is-selected').innerText;
    } else if (el && el.closest('.whistle-main__tab-content')){
      tabName = document.querySelector('.tab-label.is-selected') && document.querySelector('.tab-label.is-selected').innerText;
    } else if ( location.pathname.match('whistle/main$')&& !el && document.querySelector('.tab-item.is-active')){
      tabName = document.querySelector('.tab-item.is-active').innerText;
    }

    // 뉴스 - 화면 항목 클릭 시
    const parentTab = el && el.closest('.news-container__tab');
    if (parentTab) {
      const tab = document.querySelector('.tab-label.is-selected');
      tabName = tab && tab.innerText;
    }

    // PAGE LOAD
    if (cd && cd.tab_name) {
      tabName = cd.tab_name;
      if (location.pathname.match('/search') && cd.act_type === 'pageview') {
          sessionStorage.setItem("nth_search_tabName", cd.tab_name);
      }
    }

    // 상품 상세 페이지
    if(location.pathname.match('/product/detail') ){
      tabName = document.querySelector('.tab-label.is-selected') && document.querySelector('.tab-label.is-selected').innerText.replace(/[\d,]/g,'') ;
    } else if (location.pathname.match('/search')) {
      // 통합검색 - 검색 결과 페이지
      const searchParent = el && el.closest('.search-result__tab');
      if (el && el.matches('.tab-item')) {
        tabName = sessionStorage.getItem("nth_search_tabName");
      } else if (searchParent) {
        const tabEl = searchParent.querySelector('.tab-label.is-selected');
        tabName = tabEl && tabEl.innerText;
      } else if (el && el.querySelector('.search-header__icon-search')) {
        const tabEl = document.querySelector("button.tab-item > div.tab-label.is-selected");
        tabName = tabEl && tabEl.innerText;
      } else if (el && el.tagName.toLowerCase() === 'button' && el.parentElement.className.includes('more-button')) {
        tabName = sessionStorage.getItem("nth_search_tabName");
      } else if (document.querySelector('.is-selected.is-bottom-line-stretch')) {
        tabName = document.querySelector('.is-selected.is-bottom-line-stretch').innerText;
      }
    }else if(location.pathname.match('favorite') ){
      tabName = document.querySelector('.tab-label.is-selected') && document.querySelector('.tab-label.is-selected').innerText.replace(/\d/g,'') ;
    }

    if(location.pathname.match('myPage/review$') && document.querySelector('button[class*=review-tab-container__tab-button].active')){
      tabName = document.querySelector('button[class*=review-tab-container__tab-button].active').innerText.replace(/\d/g,'') ;
    }if ( location.pathname.match('/store/') && document.querySelector('.store-custom-tab-button.active') ){
    tabNameIt = document.querySelector('.store-custom-tab-button.active').innerText;
    tabName = tabNameIt && tabNameIt.trim();
   }else if ( location.pathname.match('news?') && document.querySelector('.tab-list .tab-label.is-selected') ){
    tabNameIt = document.querySelector('.tab-list .tab-label.is-selected').innerText;
    tabName = tabNameIt && tabNameIt.trim();
   }
    tabName = tabName && tabName.trim().replace(/[\r\n]+/g, ' ').replace(/\s{2,}/g, ' ');
    return tabName ? tabName : '';
}

function func() {
