function func() {
    var txt;
    var agent;

    agent = window && window.navigator.userAgent;
    agent = agent && agent.split('(')[1];

    if (agent.includes('Android','android','AOS')){
      txt = 'Android';
    } else if (agent.includes('iPhone','iPad','iPod')){
      txt = 'iOS';
    } else if (agent.includes('Window')){
      txt = 'Windows';
    } else if (agent.includes('Mac OS','Macintosh')){
      txt = 'MacOS';
    } else {
      txt = 'etc';
    }

    return txt;
}

