function func(){
  var cd = {{customData}}; //커스텀 이벤트 분기용
  var el = {{clickElement}}; //클릭 액션 분기용
  var event = {{activeTriggers}}; //발동 유형 분기용
  var url = {{path}};
  var txt = '';

  // activeTriggers는 1개여도 배열로 들어옴
  if (Array.isArray(event) && event[0]) {
    event = event[0].event;
  } else { return; }

  if ( !el && !cd && url.match('search') ){
    txt = "search";
  } else if (url.includes('/whistle/main') && event.match(/CLICKED/) && (el.closest('div.whistle-main-header__modal-content') || el.closest('div.whistle-task-header__modal'))) {
    txt = "popup_click";
  } else if (event.match(/CLICKED/) && el.closest('.ly_pop.ly_list.popBtm')) {
    txt = "popup_click";
  } else if (event.match(/CLICKED/) && el) {
    txt = "click";
  } else if (event.match(/CUSTOM/) && cd) {
    txt = cd.act_type || 'custom';
  } else if (event.match(/PAGELOADED|DOMREADY|WINDOWLOADED|URLCHANGED|HASHCHANGED/)) {
     txt = "pageview";
  }
  // txt && console.log('NTH >> 사용자 행동 : ' + txt);

  return txt;
}

