function func() {
    let el = {{clickElement}};
    const cd = {{customData}};

    const likes = {{AL_likeBtn_arr}};
    if (el && likes.some(cls => el.classList.contains(cls))) {
      el = el.closest('a') || null;
    }
    let price = '';

    if (el) {
      // CLICK     
      const prices = ['.price__original s','div.timedeal-item__contents > div > span.total', '.store-grid__price', '.recent-goods-item-price'];
      const selector = prices.join(', ');
      let elPrice = el.querySelector(selector);
      if (!elPrice && !(location.pathname.match('product/detail') && el.closest('.product-item')) ) {
        elPrice = document.querySelector('.prod-item__origin-price');
      }
      price = elPrice ? elPrice.innerText : '';
      const idx = price.indexOf('%');
      if (idx > 0 && idx + 1 < price.length) {
        price = price.substring(idx + 1).trim();
      }

      if ( !price && location.pathname.match('(search|category)') && el.closest('.best-product__swiper, .product-item')) {
         const priceEl = el.querySelector('.price__total');
         price = (priceEl && priceEl.innerText) || '';
      }

    } else if (cd && cd.prd_price_origin) {
      // PAGE LOAD
      price = cd.prd_price_origin;
    } else if (location.pathname.match('product/detail')){
      el = document.querySelector('.prod-item__origin-price');
      price = el ? el.innerText : '';
    }else if (!el && location.pathname.match('(favorite|myPage/recentGoods)') && document.querySelector('.recent-goods-item-price')){
      var els = document.querySelectorAll('.recent-goods-item-price');
      var prices = [];
      els.forEach((e) => {
        if (e.querySelector('.recent-goods-item-sale-rate')){
          prices.push('0');
        }else{
          prices.push(e.innerText.trim());
        }
      });
      price = prices.join('___');
    }

    price = price.replace(/[^(\d|_)]/g,'');
    return price;
}

