      const txt = elReview ? elReview.innerText : '';
      review = txt ? getReviewCnt(txt) : '';
    } else if (cd && cd.prd_review_cnt) {
      review = getReviewCnt(cd.prd_review_cnt);
    }else if (location.pathname.match('product/detail') && document.querySelector('.prod-item__feedback-review')){
      review = document.querySelector('.prod-item__feedback-review').innerText;
      if(review) review = getReviewCnt(review);
    }

    return review;
}

