function func() {
  let el = {{clickElement}};
  const likes = {{AL_likeBtn_arr}};
  var index = '';

  if (el && likes.some(cls => el.classList.contains(cls))) {
    el = el.closest('a') || null;
  }
  if (!el) return '';

  // 여러 선택자 중 가장 먼저 매칭되는 closest 요소를 반환
  const closestMatch = (element, selectors) => {
    return selectors.map(sel => element.closest(sel)).find(Boolean);
  };

  const listItemSelectors = ['.ranking-goods-card','.product-item', '.timedeal-item', '.store-grid__item', '.recent-goods-item-container'];
  const containerSelectors = ['.commerce-most-reviewed__contents', '.ranking-swiper > .swiper-wrapper', '.ranking-list', '.product-item-list', '.timedeal__list', '.swiper-slide-active', '.store-grid', '.productlist-swiper', '.favorite-goods__goods-product-content', '.category-detail__filter-view__product-list' , '.recent-goods__items-container', '.category-detail__filter-view-product-list'];
  if ( location.pathname.match('search') && el.closest('.review-recomm-item')){
    const listItem = el.closest('.review-recomm-item');
    const items = Array.from(listItem.parentElement.querySelectorAll('.review-recomm-item'));

    index = items.indexOf(listItem) + 1;
    return index;
  }
  const listItem = closestMatch(el, listItemSelectors);
  if (!listItem) return '';
  const container = closestMatch(listItem, containerSelectors);
  if (!container) return '';

  const itemSelectors = listItemSelectors.join(', ');
  const items = Array.from(container.querySelectorAll(itemSelectors));

  index = items.indexOf(listItem) + 1;
  return index;
}

