function func() {
    let el = {{clickElement}};
    const cd = {{customData}};
    const likes = {{AL_likeBtn_arr}};
    if (el && likes.some(cls => el.classList.contains(cls))) {
      el = el.closest('a') || null;
    }
    let review = '';

    if (el) {
      // CLICK
      // 리뷰어 프로필 el 재작성
      const container = el.closest('.common-review-item-container');
      if (container) {
        el = container;
      }

      // 리뷰 평점 찾아서 리턴
      const titles = ['.review__score', '.rating-score','.review-rating-score'];
      const selector = titles.join(', ');
      let elReview = el.querySelector(selector);

      if (!elReview && !el.closest('.best-review, .photo-and-video-review, .product-detail-whole-reviews, [data-id="product-detail__feedback-above-four-item"]')) {
        elReview = document.querySelector('.prod-item__feedback-score');
      }
      if (el.querySelector('.review-rating-score')) {
        elReview = el.querySelector('.review-rating-score');
      }
      if (el.querySelector('.review-rating')) {
        elReview = el.querySelector('.review-rating');
      }

      review = elReview ? elReview.innerText : '';

     // 세차장 설명(방문자 리뷰___별점___주소))
      const carWash = el.closest('.carwash_list');
      var carWashInfo = el.querySelector('ul.info');
      var carWashAdd = el.querySelector('.addr');
      if (carWash){
        review = carWashInfo.innerText;
        var washReview = review.split('별')[0].replace(/\s+/g, ''); //방문자 리뷰 43
        var washStar1 = review.split('\n')[2];  //별점
        var washStar2 = review.split('\n')[3];  //4.3
        carWashAdd = carWashAdd.innerText;
        review = washReview + '___' + washStar1 + washStar2 + '___' + carWashAdd;
        //console.log('NTH TEST carwash :::' + review);
      }

    } else if (cd && cd.prd_review_score) {
      // PAGE LOAD
      review = cd.prd_review_score;
    } else if (location.pathname.match('product/detail') && document.querySelector('.prod-item__feedback-score')){
      review = document.querySelector('.prod-item__feedback-score').innerText;
    } else if (location.pathname.match('myPage/review$') && document.querySelector(".common-review-item-container") && !el){
      var els = document.querySelectorAll(".common-review-item-container");
      var reviews = [];
      els.forEach((e) => {
        if (e.querySelector('.rating-score')){
         reviews.push(e.querySelector('.rating-score').innerText);
        }
      });
      review = reviews.join('___');
    }

    return review;
}

