function func() {
    let el = {{clickElement}};
    const cd = {{customData}};
    const likes = {{AL_likeBtn_arr}};
    if (el && likes.some(cls => el.classList.contains(cls))) {
      el = el.closest('a') || null;
    }

    if (cd && cd.act_type === 'pageview' && cd.prd_price_final) {

      return cd.prd_price_final.replace(/[^(\d|_)]/g,'');
    }

    let price = '';

    let priceEl = el && (el.querySelector('.price__total') || el.querySelector('.ranking-goods-price, .recent-goods-item-price'));
    if (!priceEl) {
      if (document.querySelector('.prod-item__max-sale-price')){
        priceEl = document.querySelector('.prod-item__max-sale-price');
      }else{
        priceEl = document.querySelector('.prod-item-sale-price, .recent-goods-item-price');
      }
    }
    price = priceEl ? priceEl.innerText : '';
    if (el && el.querySelector('.store-grid__price')){
      price =  el.querySelector('.store-grid__price') ?  el.querySelector('.store-grid__price').innerText : '';
      const idx = price.indexOf('%');
      if (idx > 0 && idx + 1 < price.length) {
        price = price.substring(idx + 1).trim();
      }
    } else if (el && location.pathname.includes('search') && el.closest('.best-product__swiper, .product-item')) {
       price = '';
    }

   if(location.pathname.match('myPage/recentGoods') && document.querySelector('.recent-goods-item-price')){
      if (!el){
        var goods = document.querySelectorAll('.recent-goods-item-price');
        var prices = [];
        goods.forEach((e) => { 
          if (e.querySelector('.recent-goods-item-sale-rate') && e.childNodes.length > 1) {
            prices.push(e.lastChild.textContent);
          }else{
            prices.push(e.innerText);
          }
        });

        price = prices.join('___');
      }else if(el && el.closest('a.recent-goods-item-button') && el.closest('a.recent-goods-item-button').querySelector('.recent-goods-item-price')){
       var pricel = el.closest('a.recent-goods-item-button').querySelector('.recent-goods-item-price').innerText.split('%');
       price = pricel.length > 1 ? pricel[pricel.length -1] : price;
     }
   }else if (location.pathname.match('order/payment')){
    if ( (!el) || (el && el.matches('.order-payment__payment-button'))){
      var els = document.querySelectorAll('.order-payment-list__product-price');
      var prices = [];
      els.forEach((e) => {
         prices.push(e.innerText);
      });
      price = prices.join('___');
    }
   }else if (el && el.matches('.recent-order-item') && el.querySelector('.recent-order-item__detail-desc__price')){
     price = el.querySelector('.recent-order-item__detail-desc__price').innerText.trim();
   }else if (el && el.matches('.cart-selected-goods__goods-buy-button') && location.pathname.match('order/cart')){
       el = el.closest('[data-goods-id]');
       price = el.querySelector('.cart-selected-goods__goods-price').innerText;
   }else if (el && el.matches('.cart-selected-goods__total-button') && document.querySelector('.cart-selected-goods__goods-price') && location.pathname.match('order/cart')){
      var els = document.querySelectorAll('.cart-selected-goods__goods-price');
      var prices = [];
      els.forEach((e) => {
        if (!e.parentElement.parentElement.querySelector('.cart-selected-goods__goods-name')){
         prices.push(e.innerText);
        }
      });
      price = prices.join('___');
    }else if (el && el.querySelector('.timedeal-item__price > .total') && el.querySelector('.timedeal-item__price > .discount') ){
     price = el.querySelector('.timedeal-item__price > .total').innerText;
    }

    if (location.pathname.includes('search') && el && el.closest('.best-product__swiper, .product-item')) {
       priceEl = el.querySelector('.price__total');
       price = (priceEl && priceEl.innerText) || '';
   }
    if (price.match('%(.+)') ){
      price = price.match('%(.+)')[1];
    }

   if (location.pathname.match('myPage$') ) {
     if (!el){
       return '';
     }else{
       var item = el.closest('.recent-order-item, .product-item, .recent-goods-item-container, .store-grid__item, .ranking-goods-card, .product-item__thumb');
       var like = el.closest('.btn-like, .ranking-goods-like,.bottm-btn-like, .favorite-button');
       if( !item && !like){
         return '';
       }
     }

       priceEl = el.querySelector('.price__total, .recent-order-item__detail-desc__price');
       price = (priceEl && priceEl.innerText) || '';
   }
    return price.replace(/[^(\d|_)]/g,'');;
}

