function func() {
  const el = {{clickElement}};
  const cd = {{customData}};
  const imElements = {{AL_impression}};
  let flag = false;
  var url = '';
  if (cd && cd.exh_url) {
    return cd.exh_url;
  } else if (cd && cd.banner_url) {
    return cd.banner_url;
  }

  if (el && imElements){
    imElements.forEach(e => {
      if (location.pathname === e.page_id &&  el.closest(e.css) ) {
        flag = true;
      } else if (el.tagName === 'img') {
        flag = true;
      }
    });
  }

  let code = '';
  if (el && location.pathname.match('main/home') && el.closest('.commerce-popup__swiper-wrap')){
        if (el.closest('[data-main-popup-url]')){
            url = el.closest('[data-main-popup-url]').dataset.mainPopupUrl;
        }else if(el.querySelector('[data-main-popup-url]')){
          url = el.querySelector('[data-main-popup-url]').dataset.mainPopupUrl;
        }
  } else if (el && location.pathname.match('main$')) {
        if (el.closest('[data-landing-url')){
            url = el.closest('[data-landing-url]').dataset.landingUrl;
        }
  } else if (flag && el && el.tagName.toLowerCase() === 'a') {
    return el.href;
  } else if (flag && el && el.tagName.toLowerCase() === 'img') {
    return el.getAttribute('src') || el.getAttribute('data-value') || '';
  }

  return url;
}

function func() {
  let el = {{clickElement}};
  const cd = {{customData}};
  if (cd && cd.order) {
    // 라운드 메인 상단 메인 배너
