    const items = Array.from(list.querySelectorAll('.navigation-bottom__menu'));
    const index = items.indexOf(bottomMenuItem) + 1;
    return index;
  }

  return '';
}

function func() {
    const el = {{clickElement}};
    let cardName = '';

    if (el) {
        // 1차: whistle-main__tab-content 내부
        const inMainTab = el.closest('.whistle-main__tab-content');
        if (inMainTab) {
            const typeEl = el.querySelector('.whistle-card-container__type');
            if (typeEl && typeEl.innerText) {
                cardName = typeEl.innerText;
            }

            // fallback: 리뷰 카드일 경우
            if (!cardName) {
                const reviewCard = el.closest('.whistle-card-container.long.review');
                const childTypeEl = reviewCard && reviewCard.querySelector('.whistle-card-container__type');
                if (childTypeEl && childTypeEl.innerText) {
                    cardName = childTypeEl.innerText;
                }
            }
        }

        // 2차: product-item 내부
        const inProduct = el.closest('.product-item');
        if (!cardName && inProduct) {
            const titleEl = inProduct.querySelector('p.title');
            if (titleEl && titleEl.innerText) {
                cardName = titleEl.innerText;
            }
        }
    }

    // 공백 및 줄바꿈 제거
    return (cardName || '').replace(/\s+/g, ' ').trim();
}

