function func() {
  let el = {{clickElement}};
  const imElements = {{AL_impression}};
  var index = '';
  const cd = {{customData}};
  if (cd && cd.banner_order) {
    return cd.banner_order;
  }

  if (el && imElements){
    if (el.closest('[data-swiper-slide-index]')){
      index = el.closest('[data-swiper-slide-index]').dataset.swiperSlideIndex;
      index = index ? Math.floor(index) + 1 : 0;
    }else{
      imElements.forEach(e => {
        if (location.pathname === e.page_id &&  el.closest(e.css) ) {
          const closestMatch = (element, selectors) => {
            return selectors.map(sel => element.closest(sel)).find(Boolean);
          };

          const listItemSelectors = ['.swiper-slide'];
          const containerSelectors = ['.swiper-wrapper'];

          const listItem = closestMatch(el, listItemSelectors);
          if (!listItem) return '';
          const container = closestMatch(listItem, containerSelectors);
          if (!container && !listItem) return '';

          const itemSelectors = listItemSelectors.join(', ');
          const items = Array.from(container.querySelectorAll(itemSelectors));

          index = items.indexOf(listItem) + 1;
        } else if (el.tagName === 'img') {
          return '';
        }
      });
    }
  }else{
    return '';
  }

  return index;
}

