function func() {
  //console.log('NTM true_list 구문 시작');
  const url = location.href;

  if (url.includes('/wash/auth/pay/payStep1')) { // 세차 이용권 구매 페이지
    const checked = document.querySelector('input:checked');
    const radiobox = checked ? checked.closest('span.radioBox') : null;
    const titleEl = radiobox ? radiobox.querySelector('p.ttl') : null;

    if (!titleEl) return '';

    // 텍스트 노드만 추출 (자식 중 텍스트 노드 필터링)
    const text = Array.from(titleEl.childNodes)
      .filter(node => node.nodeType === Node.TEXT_NODE)
      .map(node => node.textContent.trim())
      .join(' '); // 혹시 여러 텍스트 노드가 있을 경우 대비

    return text;
  }

  if (url.includes('/wash/auth/pay/payStep2')) {
    // 1. 이용권 정보
    const voucherEl = document.querySelector('.list_group.pay .ttl + .data');
    const voucherText = voucherEl ? voucherEl.innerText.trim() : '';

    // 2. 결제방식 (payType)
    let payTypeText = '';
    const payTypeInput = document.querySelector('input[name="payType"]:checked');
    if (payTypeInput) {
        const radiobox = payTypeInput.closest('span.radioBox');
        const ttlEl = radiobox ? radiobox.querySelector('p.ttl') : null;
        if (ttlEl) {
            payTypeText = ttlEl.innerText.trim();
        }
    }

    // 3. 결제수단 (payMethod)
    let payMethodText = '';
    const payMethodInput = document.querySelector('input[name="paymentMethod"]:checked');
    if (payMethodInput) {
        const label = payMethodInput.closest('label');
        const methodTextEl = label ? label.querySelector('span') : null;
        if (methodTextEl) {
            payMethodText = methodTextEl.innerText.trim();
        }
    }

    // 4. 휘슬 상품권
    let voucherInputText = '휘슬 상품권 미선택';
    const voucherInput = document.querySelector('.btn_voucher input');
    if (voucherInput) {
        const rawText = voucherInput.value.trim();
        if (rawText) {
            voucherInputText = rawText;
        }
    }

    // 5. 결합해서 리턴
    //return `${voucherText}___${payTypeText}___${payMethodText}___${voucherInputText}`;
    return `${voucherText}___${payTypeText}___${voucherInputText}`;
  }

}

